        });

        return reply.status(200).send({
          success: true,
          message: 'Global automatic health checks berhasil dinonaktifkan',
        });
      } catch (error: any) {
        logger.error('Failed to stop global automatic health checks', error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
