/**
 * Scraper Health Check Service Tests
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import {
  scraperHealthCheckService,
  ScraperHealthCheckService,
  HealthStatus,
} from './scraperHealthCheckService';
import { scraperSourceService } from './scraperSourceService';

// Mock dependencies
vi.mock('./loggerService', () => ({
  logger: {
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
    debug: vi.fn(),
  },
}));

vi.mock('./socketManager', () => ({
  getSocketInstance: vi.fn(() => ({
    emit: vi.fn(),
  })),
}));

vi.mock('./scraperSourceService', () => ({
  scraperSourceService: {
    getSource: vi.fn(),
    getEnabledSources: vi.fn(),
    updateStats: vi.fn(),
  },
}));

vi.mock('@prisma/client', () => {
  const mockPrisma = {
    scraperSource: {
      findUnique: vi.fn(),
      update: vi.fn(),
    },
    scraperLog: {
      findMany: vi.fn(),
    },
  };
  return {
    PrismaClient: vi.fn(() => mockPrisma),
  };
});

// Mock fetch globally
global.fetch = vi.fn();

describe('ScraperHealthCheckService', () => {
  let service: ScraperHealthCheckService;

  beforeEach(() => {
    service = new ScraperHealthCheckService();
    vi.clearAllMocks();
  });

  afterEach(() => {
    service.stopGlobalAutoCheck();
  });

  describe('checkSourceHealth', () => {
    it('should return HEALTHY status for successful check', async () => {
      // Mock source
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // Mock successful fetch
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      const result = await service.checkSourceHealth('source-1');

      expect(result.status).toBe(HealthStatus.HEALTHY);
      expect(result.sourceId).toBe('source-1');
      expect(result.sourceName).toBe('Test Source');
      expect(result.responseTime).toBeDefined();
      expect(result.statusCode).toBe(200);
      expect(result.consecutiveFailures).toBe(0);
      expect(result.details?.isAccessible).toBe(true);
      expect(result.details?.hasValidResponse).toBe(true);
    });

    it('should return DEGRADED status for slow response', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // Mock slow fetch (delay before resolving)
      vi.mocked(global.fetch).mockImplementation(
        () =>
          new Promise(resolve => {
            setTimeout(() => {
              resolve({
                ok: true,
                status: 200,
              } as Response);
            }, 3500); // Exceeds default 3000ms threshold
          })
      );

      const result = await service.checkSourceHealth('source-1', {
        performanceThreshold: 3000,
      });

      expect(result.status).toBe(HealthStatus.DEGRADED);
      expect(result.error).toContain('exceeds threshold');
      expect(result.details?.hasValidResponse).toBe(true);
      expect(result.details?.meetsPerformanceThreshold).toBe(false);
    });

    it('should return UNHEALTHY status for connection failure', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // Mock connection failure
      vi.mocked(global.fetch).mockRejectedValue(new Error('ECONNREFUSED'));

      const result = await service.checkSourceHealth('source-1');

      expect(result.status).toBe(HealthStatus.UNHEALTHY);
      expect(result.error).toContain('Connection failed');
      expect(result.consecutiveFailures).toBe(1);
      expect(result.details?.isAccessible).toBe(false);
    });

    it('should return UNHEALTHY status for timeout', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // Mock timeout
      vi.mocked(global.fetch).mockImplementation(
        () =>
          new Promise((_, reject) => {
            setTimeout(() => {
              const error = new Error('Timeout');
              error.name = 'AbortError';
              reject(error);
            }, 100);
          })
      );

      const result = await service.checkSourceHealth('source-1', {
        timeout: 50,
      });

      expect(result.status).toBe(HealthStatus.UNHEALTHY);
      expect(result.error).toContain('Timeout');
    });

    it('should track consecutive failures', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);
      vi.mocked(global.fetch).mockRejectedValue(new Error('Connection failed'));

      // First failure
      const result1 = await service.checkSourceHealth('source-1');
      expect(result1.consecutiveFailures).toBe(1);

      // Second failure
      const result2 = await service.checkSourceHealth('source-1');
      expect(result2.consecutiveFailures).toBe(2);

      // Third failure
      const result3 = await service.checkSourceHealth('source-1');
      expect(result3.consecutiveFailures).toBe(3);
    });

    it('should reset consecutive failures on success', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // First failure
      vi.mocked(global.fetch).mockRejectedValueOnce(new Error('Connection failed'));
      const result1 = await service.checkSourceHealth('source-1');
      expect(result1.consecutiveFailures).toBe(1);

      // Success
      vi.mocked(global.fetch).mockResolvedValueOnce({
        ok: true,
        status: 200,
      } as Response);
      const result2 = await service.checkSourceHealth('source-1');
      expect(result2.consecutiveFailures).toBe(0);
    });

    it('should handle invalid HTTP status codes', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        headers: {},
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);

      // Mock 404 response
      vi.mocked(global.fetch).mockResolvedValue({
        ok: false,
        status: 404,
      } as Response);

      const result = await service.checkSourceHealth('source-1');

      expect(result.status).toBe(HealthStatus.UNHEALTHY);
      expect(result.statusCode).toBe(404);
      expect(result.error).toContain('Invalid response');
    });
  });

  describe('checkAllSources', () => {
    it('should check all enabled sources', async () => {
      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
        { id: 'source-2', name: 'Source 2', url: 'https://example2.com', enabled: true },
        { id: 'source-3', name: 'Source 3', url: 'https://example3.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue(
        mockSources as any
      );
      vi.mocked(scraperSourceService.getSource).mockImplementation(async (id: string) => {
        return mockSources.find(s => s.id === id) as any;
      });

      // Mock successful responses
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      const results = await service.checkAllSources();

      expect(results).toHaveLength(3);
      expect(results.every(r => r.status === HealthStatus.HEALTHY)).toBe(true);
    });

    it('should handle mixed success and failure', async () => {
      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
        { id: 'source-2', name: 'Source 2', url: 'https://example2.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue(
        mockSources as any
      );
      vi.mocked(scraperSourceService.getSource).mockImplementation(async (id: string) => {
        return mockSources.find(s => s.id === id) as any;
      });

      // Mock mixed responses
      vi.mocked(global.fetch)
        .mockResolvedValueOnce({
          ok: true,
          status: 200,
        } as Response)
        .mockRejectedValueOnce(new Error('Connection failed'));

      const results = await service.checkAllSources();

      expect(results).toHaveLength(2);
      expect(results[0].status).toBe(HealthStatus.HEALTHY);
      expect(results[1].status).toBe(HealthStatus.UNHEALTHY);
    });
  });

  describe('Auto health checks', () => {
    it('should start and stop auto check for a source', async () => {
      vi.useFakeTimers();

      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Start auto check with short interval
      service.startAutoCheck('source-1', { checkInterval: 1000 });

      // Wait for initial check
      await vi.runAllTimersAsync();

      // Stop auto check
      service.stopAutoCheck('source-1');

      vi.useRealTimers();
    });

    it('should start and stop global auto check', async () => {
      vi.useFakeTimers();

      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue(
        mockSources as any
      );
      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSources[0] as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Start global auto check
      await service.startGlobalAutoCheck({ checkInterval: 1000 });

      expect(service.isAutoCheckActive()).toBe(true);

      // Stop global auto check
      service.stopGlobalAutoCheck();

      expect(service.isAutoCheckActive()).toBe(false);

      vi.useRealTimers();
    });
  });

  describe('Health status management', () => {
    it('should get source health status', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Perform check to create history
      await service.checkSourceHealth('source-1');

      const status = service.getSourceHealthStatus('source-1');

      expect(status).toBeDefined();
      expect(status?.sourceId).toBe('source-1');
      expect(status?.consecutiveFailures).toBe(0);
      expect(status?.lastSuccessfulCheck).toBeDefined();
    });

    it('should reset health history', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Perform check
      await service.checkSourceHealth('source-1');

      // Verify history exists
      let status = service.getSourceHealthStatus('source-1');
      expect(status).toBeDefined();

      // Reset history
      service.resetHealthHistory('source-1');

      // Verify history is cleared
      status = service.getSourceHealthStatus('source-1');
      expect(status).toBeNull();
    });

    it('should get all health statuses', async () => {
      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
        { id: 'source-2', name: 'Source 2', url: 'https://example2.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getSource).mockImplementation(async (id: string) => {
        return mockSources.find(s => s.id === id) as any;
      });
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Perform checks
      await service.checkSourceHealth('source-1');
      await service.checkSourceHealth('source-2');

      const allStatuses = service.getAllHealthStatuses();

      expect(allStatuses.size).toBe(2);
      expect(allStatuses.has('source-1')).toBe(true);
      expect(allStatuses.has('source-2')).toBe(true);
    });

    it('should clear all health history', async () => {
      const mockSource = {
        id: 'source-1',
        name: 'Test Source',
        url: 'https://example.com',
        enabled: true,
      };

      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSource as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Perform check
      await service.checkSourceHealth('source-1');

      // Verify history exists
      let allStatuses = service.getAllHealthStatuses();
      expect(allStatuses.size).toBe(1);

      // Clear all history
      service.clearAllHealthHistory();

      // Verify all history is cleared
      allStatuses = service.getAllHealthStatuses();
      expect(allStatuses.size).toBe(0);
    });
  });

  describe('Health statistics', () => {
    it('should get health statistics', async () => {
      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
        { id: 'source-2', name: 'Source 2', url: 'https://example2.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue(
        mockSources as any
      );

      const statistics = await service.getHealthStatistics();

      expect(statistics).toBeDefined();
      expect(statistics.total).toBe(2);
      expect(statistics.sources).toHaveLength(2);
    });
  });

  describe('Edge cases', () => {
    it('should handle source not found', async () => {
      vi.mocked(scraperSourceService.getSource).mockRejectedValue(
        new Error('Source not found')
      );

      await expect(service.checkSourceHealth('invalid-id')).rejects.toThrow(
        'Source not found'
      );
    });

    it('should handle empty enabled sources list', async () => {
      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue([]);

      const results = await service.checkAllSources();

      expect(results).toHaveLength(0);
    });

    it('should not start global auto check if already enabled', async () => {
      vi.useFakeTimers();

      const mockSources = [
        { id: 'source-1', name: 'Source 1', url: 'https://example1.com', enabled: true },
      ];

      vi.mocked(scraperSourceService.getEnabledSources).mockResolvedValue(
        mockSources as any
      );
      vi.mocked(scraperSourceService.getSource).mockResolvedValue(mockSources[0] as any);
      vi.mocked(global.fetch).mockResolvedValue({
        ok: true,
        status: 200,
      } as Response);

      // Start first time
      await service.startGlobalAutoCheck({ checkInterval: 1000 });
      expect(service.isAutoCheckActive()).toBe(true);

      // Try to start again
      await service.startGlobalAutoCheck({ checkInterval: 1000 });
      expect(service.isAutoCheckActive()).toBe(true);

      service.stopGlobalAutoCheck();
      vi.useRealTimers();
    });
  });
});

